            WriteLiteral(@"<script>
    function confermDelete() {
        if (confirm('Delete This Produit ?')) { return true; }
        else { event.stopPropagation(); event.preventDefault(); };
    }
</script>
<script>
    function filterTable() {
        var input = document.getElementById(""searchInput"");
        var filter = input.value.toLowerCase();
        var rows = document.querySelectorAll(""#productTableBody tr"");

        rows.forEach(row => {
            var nameCell = row.querySelector(""td:first-child""); 
            if (nameCell) {
                var nameValue = nameCell.textContent.toLowerCase();
                row.style.display = nameValue.includes(filter) ? """" : ""none"";
            }
        });
    }

    function sortTable(n) {
        var table = document.querySelector("".table tbody"");
        var rows = Array.from(table.rows);
        var ascending = table.dataset.sortOrder !== ""asc"";

        rows.sort((rowA, rowB) => {
            var cellA = rowA.cells[n].textContent.trim().toLowerC");
            WriteLiteral(@"ase();
            var cellB = rowB.cells[n].textContent.trim().toLowerCase();
            return ascending ? cellA.localeCompare(cellB, undefined, { numeric: true }) : cellB.localeCompare(cellA, undefined, { numeric: true });
        });

        table.innerHTML = """";
        rows.forEach(row => table.appendChild(row));

        table.dataset.sortOrder = ascending ? ""asc"" : ""desc"";
    }
</script>

